import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if len(unvisited_customers) == 0:
        return None  # No customers left to visit, might need to rest or end the route

    distances = np.linalg.norm(unvisited_customers - cur_truck_pos, axis=1)
    urgency_scores = distances  # simple placeholder, assume urgency is understood as inverse of distance

    best_node = None
    min_score = np.inf

    for idx, distance in enumerate(distances):
        is_closest = True  # to check if the current truck is the closest
        for other_truck_pos in all_truck_pos:
            if not np.array_equal(other_truck_pos, cur_truck_pos):
                other_distance = np.linalg.norm(unvisited_customers[idx] - other_truck_pos)
                if other_distance < distance:
                    is_closest = False
                    break

        if is_closest and urgency_scores[idx] < min_score:
            min_score = urgency_scores[idx]
            best_node = idx

    if best_node is None:
        return None  # indicates a strategic wait or end route if no suitable customer is prioritized
    else:
        return best_node
